import { useEffect, useState, useContext } from 'react';
import { AuthContext } from '../context/AuthContext';
import api from '../services/api';
import TaskForm from '../components/TaskForm'; // TaskForm import kiya

const Dashboard = () => {
  const [tasks, setTasks] = useState([]);
  const { user, logout } = useContext(AuthContext);

  // 1. Database se tasks fetch karna
  const fetchTasks = async () => {
    try {
      const res = await api.get('/tasks');
      setTasks(res.data);
    } catch (err) {
      console.error('Tasks fetch karne mein error:', err);
    }
  };

  useEffect(() => {
    fetchTasks();
  }, []);

  // 2. Task Status update karne ka logic (To-Do -> Done)
  const updateStatus = async (id) => {
    try {
      await api.patch(`/tasks/${id}`, { status: 'Done' });
      fetchTasks(); // List ko refresh karo bina page reload kiye
    } catch (err) {
      alert('Status update nahi ho paya');
    }
  };

  // 3. Overdue Tasks calculate karo
  const overdueCount = tasks.filter(
    (t) => new Date(t.deadline) < new Date() && t.status !== 'Done'
  ).length;

  return (
    <div style={{ padding: '20px', fontFamily: 'Arial, sans-serif' }}>
      <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <h1>Dashboard ({user?.role})</h1>
        <button onClick={logout} style={{ padding: '10px', background: '#ff4444', color: 'white', border: 'none', borderRadius: '5px', cursor: 'pointer' }}>
          Logout
        </button>
      </header>

      {/* Metrics Section */}
      <div style={{ display: 'flex', gap: '20px', margin: '20px 0' }}>
        <div style={{ border: '1px solid #ccc', padding: '15px', borderRadius: '5px', flex: 1 }}>
          <strong>Total Tasks:</strong> {tasks.length}
        </div>
        <div style={{ border: '1px solid #ff0000', padding: '15px', borderRadius: '5px', flex: 1, color: 'red' }}>
          <strong>Overdue Tasks:</strong> {overdueCount}
        </div>
      </div>

      {/* Admin Panel: Sirf Admin ko dikhega */}
      {user?.role === 'Admin' && (
        <div style={{ background: '#f0f4f8', padding: '20px', borderRadius: '8px', marginBottom: '20px', border: '1px solid #d1d9e0' }}>
          <h3 style={{ marginTop: 0 }}>Admin Panel: New Task</h3>
          <TaskForm onTaskCreated={fetchTasks} />
        </div>
      )}

      {/* Task List Section */}
      <h3>My Tasks</h3>
      {tasks.length === 0 ? <p>Koi task nahi mil raha.</p> : (
        <ul style={{ listStyle: 'none', padding: 0 }}>
          {tasks.map((t) => (
            <li key={t._id} style={{ padding: '15px', borderBottom: '1px solid #eee', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <div>
                <span style={{ fontSize: '1.1em', fontWeight: 'bold' }}>{t.title}</span>
                <br />
                <small style={{ color: '#666' }}>
                  Status: <b>{t.status}</b> | Deadline: {new Date(t.deadline).toLocaleDateString()}
                </small>
              </div>
              
              {/* Mark as Done Button: Agar task done nahi hai tabhi dikhega */}
              {t.status !== 'Done' && (
                <button 
                  onClick={() => updateStatus(t._id)}
                  style={{ padding: '8px 12px', background: '#28a745', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer' }}
                >
                  Mark as Done
                </button>
              )}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
};

export default Dashboard;
